// Color palette: 2056+ distinct hues using prime rotation + saturation variation
export function getCaseColor(index: number): string {
  const cycle = Math.floor(index / 360);
  const hue = (index * 37) % 360;
  const sat = 65 + (cycle * 7) % 15;
  return `hsl(${hue}, ${sat}%, 55%)`;
}
